INSERT INTO public.products (id, category_id, pharmacy_id, sku, name, slug, concentration, presentation, short_description, long_description, price_current, estimated_deadline_days, active, featured) VALUES ('e1000000-0000-0000-0000-000000000002', 'a1000000-0000-0000-0000-000000000002', 'b1000000-0000-0000-0000-000000000001', 'ACIDO-RETI-001', 'Ácido Retinoico 0.05%', 'acido-retinoico-005', '0.05%', 'Creme 30g', 'Creme dermatológico de ácido retinoico 0.05% para tratamento de acne e envelhecimento', 'Creme dermatológico manipulado com ácido retinoico na concentração de 0.05%. Indicado para acne moderada e sinais de envelhecimento. Uso noturno conforme orientação médica.', 145.00, 5, true, false) ON CONFLICT (id) DO NOTHING;
