INSERT INTO public.products (id, category_id, pharmacy_id, sku, name, slug, concentration, presentation, short_description, long_description, price_current, estimated_deadline_days, active, featured) VALUES ('e1000000-0000-0000-0000-000000000004', 'a1000000-0000-0000-0000-000000000005', 'b1000000-0000-0000-0000-000000000002', 'VITD3-CAP-001', 'Vitamina D3 10000 UI', 'vitamina-d3-10000-ui', '10000 UI', 'Cápsulas (60 unidades)', 'Cápsulas de vitamina D3 manipulada 10000 UI para suplementação', 'Vitamina D3 (colecalciferol) manipulada na concentração de 10000 UI por cápsula. Indicada para correção de deficiência de vitamina D. Administração oral uma vez ao dia ou conforme prescrição.', 95.00, 5, true, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.products (id, category_id, pharmacy_id, sku, name, slug, concentration, presentation, short_description, long_description, price_current, estimated_deadline_days, active, featured) VALUES ('e1000000-0000-0000-0000-000000000005', 'a1000000-0000-0000-0000-000000000003', 'b1000000-0000-0000-0000-000000000001', 'ONDANS-SUP-001', 'Ondansetrona 8mg Supositório', 'ondansetrona-8mg-supositorio', '8mg', 'Supositório (10 unidades)', 'Supositório de ondansetrona 8mg para controle de náuseas oncológicas', 'Ondansetrona 8mg em supositório magistral para pacientes oncológicos com dificuldade de administração oral. Antiemético de alta eficácia para náuseas e vômitos induzidos por quimioterapia.', 320.00, 10, true, false) ON CONFLICT (id) DO NOTHING;
